function createGameLogicRadarColorSaveState(
  red: number,
  green: number,
  blue: number,
  alpha: number,
): GameLogicRadarColorSaveState {
  return { red, green, blue, alpha };
}

function cloneGameLogicRadarColorSaveState(
  color: GameLogicRadarColorSaveState,
): GameLogicRadarColorSaveState {
  return { ...color };
}

