  /**
   * Source parity: explicit script-team membership assignment.
   */
  setScriptTeamMembers(teamName: string, entityIds: readonly number[]): boolean {
    const team = this.getOrCreateScriptTeamRecord(teamName);
    if (!team) {
      return false;
    }

    const nextMembers = new Set<number>();
    for (const entityIdRaw of entityIds) {
      if (!Number.isFinite(entityIdRaw)) {
        continue;
      }
      const entityId = Math.trunc(entityIdRaw);
      if (!this.spawnedEntities.has(entityId)) {
        continue;
      }
      nextMembers.add(entityId);
    }
    team.memberEntityIds = nextMembers;
    team.created = true;
    this.scriptTeamCreatedAutoClearFrameByName.delete(team.nameUpper);
    return true;
  }

  /**
   * Source parity support: bind a script-team record to a TeamPrototype name.
   */
  setScriptTeamPrototype(teamName: string, prototypeTeamName: string): boolean {
    const team = this.getOrCreateScriptTeamRecord(teamName);
    const prototypeRecord = this.getOrCreateScriptTeamRecord(prototypeTeamName);
    if (!team || !prototypeRecord) {
      return false;
    }
    const prototypeNameUpper = prototypeRecord.nameUpper;
    if (team.prototypeNameUpper === prototypeNameUpper) {
      return true;
    }

    this.unregisterScriptTeamPrototypeInstance(team);
    team.prototypeNameUpper = prototypeNameUpper;
    this.registerScriptTeamPrototypeInstance(team);
    return true;
  }

  /**
   * Source parity: ScriptActions::doSetTeamState -> Team::setState.
   * Uses getTeamNamed-style single-team resolution and does not implicitly create teams.
   */
  setScriptTeamState(teamName: string, stateName: string): boolean {
    const team = this.getScriptTeamRecord(teamName);
    if (!team) {
      return false;
    }

    const normalizedStateName = stateName.trim();
    team.stateName = normalizedStateName;
    return true;
  }

  /**
   * Source parity: Team::isCreated toggle.
   */
  setScriptTeamCreated(teamName: string, created: boolean): boolean {
    const team = this.getOrCreateScriptTeamRecord(teamName);
    if (!team) {
      return false;
    }
    team.created = created;
    this.scriptTeamCreatedReadyFrameByName.delete(team.nameUpper);
    this.scriptTeamCreatedAutoClearFrameByName.delete(team.nameUpper);
    return true;
  }

  /**
   * Source parity: Team controlling player side override.
   */
  setScriptTeamControllingSide(teamName: string, side: string | null): boolean {
    const team = this.getScriptTeamRecord(teamName) ?? this.getOrCreateScriptTeamRecord(teamName);
    if (!team) {
      return false;
    }

    if (side === null) {
      team.controllingSide = null;
      team.controllingPlayerToken = null;
      return true;
    }

    const normalizedSide = this.resolveScriptPlayerSideFromInput(side);
    if (!normalizedSide) {
      return false;
    }

    team.controllingSide = normalizedSide;
    team.controllingPlayerToken = this.resolveScriptControllingPlayerTokenFromInput(side, normalizedSide);
    return true;
  }

  /**
   * Source parity: ScriptActions::doTransferTeamToPlayer uses getTeamNamed.
   * Applies to one resolved team and does not implicitly create teams.
   */
  /* @internal */ transferScriptTeamToSide(teamName: string, side: string): boolean {
    const team = this.getScriptTeamRecord(teamName);
    if (!team) {
      return false;
    }
    const normalizedSide = this.resolveScriptPlayerSideFromInput(side);
    if (!normalizedSide) {
      return false;
    }
    team.controllingSide = normalizedSide;
    team.controllingPlayerToken = this.resolveScriptControllingPlayerTokenFromInput(side, normalizedSide);
    return true;
  }

  /**
   * Source parity helper: TeamTemplateInfo priority fields used by
   * ScriptActions::doTeamIncreasePriority / doTeamDecreasePriority.
   */
  setScriptTeamPriorityValues(
    teamName: string,
    productionPriority: number,
    successIncrease: number,
    failureDecrease: number,
  ): boolean {
    const team = this.getOrCreateScriptTeamRecord(teamName);
    if (!team) {
      return false;
    }
    team.productionPriority = Math.trunc(productionPriority);
    team.productionPrioritySuccessIncrease = Math.trunc(successIncrease);
    team.productionPriorityFailureDecrease = Math.trunc(failureDecrease);
    return true;
  }

  getScriptTeamPriorityState(teamName: string): {
    productionPriority: number;
    successIncrease: number;
    failureDecrease: number;
  } | null {
    const team = this.getScriptTeamRecord(teamName);
    if (!team) {
      return null;
    }
    return {
      productionPriority: team.productionPriority,
      successIncrease: team.productionPrioritySuccessIncrease,
      failureDecrease: team.productionPriorityFailureDecrease,
    };
  }

  /* @internal */ removeScriptTeamOverrideRelationToTeam(teamName: string, otherTeamName: string): boolean {
    const sourceSides = this.resolveScriptTeamSidesForRelationship(teamName);
    const targetSides = this.resolveScriptTeamSidesForRelationship(otherTeamName);
    if (sourceSides.length === 0 || targetSides.length === 0) {
      return false;
    }

    for (const sourceSide of sourceSides) {
      for (const targetSide of targetSides) {
        this.removeTeamRelationship(sourceSide, targetSide);
      }
    }
    return true;
  }

  /* @internal */ removeScriptTeamAllOverrideRelations(teamName: string): boolean {
    const sourceSides = this.resolveScriptTeamSidesForRelationship(teamName);
    if (sourceSides.length === 0) {
      return false;
    }

    for (const sourceSide of sourceSides) {
      this.clearRelationshipOverridesForSourceSide(sourceSide);
    }
    return true;
  }

  /* @internal */ removeScriptTeamOverrideRelationToPlayer(teamName: string, playerSide: string): boolean {
    const sourceSides = this.resolveScriptTeamSidesForRelationship(teamName);
    const targetSide = this.normalizeSide(playerSide);
    if (sourceSides.length === 0 || !targetSide) {
      return false;
    }

    for (const sourceSide of sourceSides) {
      this.removeTeamRelationship(sourceSide, targetSide);
    }
    return true;
  }

  /* @internal */ removeScriptPlayerOverrideRelationToTeam(playerSide: string, otherTeamName: string): boolean {
    const sourceSide = this.normalizeSide(playerSide);
    const targetSides = this.resolveScriptTeamSidesForRelationship(otherTeamName);
    if (!sourceSide || targetSides.length === 0) {
      return false;
    }

    for (const targetSide of targetSides) {
      this.removePlayerRelationship(sourceSide, targetSide);
    }
    return true;
  }

  /* @internal */ validateScriptSpecialPowerCommandButtonExecution(
    sourceEntity: MapEntity,
    commandButtonDef: CommandButtonDef,
    target: ScriptCommandButtonTarget,
  ): {
    specialPowerName: string;
    normalizedSpecialPowerName: string;
    commandOption: number;
  } | null {
    const resolved = this.resolveScriptSpecialPowerCommandButtonExecution(sourceEntity, commandButtonDef);
    if (!resolved) {
      return null;
    }

    const { commandOption } = resolved;
    const needsObjectTarget = (commandOption & SCRIPT_COMMAND_OPTION_NEED_OBJECT_TARGET) !== 0;
    const needsTargetPosition = (commandOption & SCRIPT_COMMAND_OPTION_NEED_TARGET_POS) !== 0;

    if (target.kind === 'NONE') {
      if (needsObjectTarget || needsTargetPosition) {
        return null;
      }
    } else if (target.kind === 'OBJECT') {
      if (!needsObjectTarget) {
        return null;
      }
      if (!isSpecialPowerObjectRelationshipAllowed(commandOption, this.getTeamRelationship(sourceEntity, target.targetEntity))) {
        return null;
      }
    } else if (!needsTargetPosition) {
      return null;
    }

    return resolved;
  }

  /* @internal */ activateCommandButtonHuntForEntity(
    entity: MapEntity,
    commandButtonName: string,
    mode: CommandButtonHuntMode,
  ): void {
    entity.commandButtonHuntButtonName = commandButtonName.trim().toUpperCase();
    entity.commandButtonHuntMode = mode;
    entity.commandButtonHuntNextScanFrame = this.frameCounter;
    // Source parity: setCommandButton() forces aiIdle(CMD_FROM_AI) before arming.
    this.applyCommand({ type: 'stop', entityId: entity.id, commandSource: 'AI' });
    // Source parity: setCommandButton() immediately runs one update tick.
    this.updateCommandButtonHuntForEntity(entity);
  }

